import React from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { Book, CashCoin } from "react-bootstrap-icons";

const ClientNav = ({ setDrawer }) => {
  const ActiveCred = useSelector((state) => state.cred.activeCred);
  const Navigate = useNavigate();
  return (
    <>
      <p
        onClick={() => {
          setDrawer(false);
          Navigate(`patients/patient/finance/${ActiveCred.linker}`);
        }}
      >
        <strong className="nav-link text-truncate">
          <CashCoin /> Finances
        </strong>
      </p>
      <hr />{" "}
      <p
        onClick={() => {
          setDrawer(false);
          Navigate(`patients/patient/health/${ActiveCred.linker}`);
        }}
      >
        <strong className="nav-link text-truncate">
          <Book /> Health Records
        </strong>
      </p>
      <hr />
    </>
  );
};

export default ClientNav;
