import React from "react";
import { useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import { Dropdown } from "react-bootstrap";
import { PersonGear } from "react-bootstrap-icons";

const AdminNav = ({ setDrawer }) => {
  const navigate = useNavigate();
  const inst = useSelector((state) => state.inst.activeInst);
  return (
    <>
      <Dropdown style={{ width: "100%" }}>
        <Dropdown.Toggle variant="transparent" className="nav-link">
          <PersonGear /> Admin{" "}
        </Dropdown.Toggle>
        <Dropdown.Menu variant="dark">
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`staffs`);
              }}
            >
              Staffs
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`modes`);
              }}
            >
              Payment Modes
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`service-categories`);
              }}
            >
              Service Categories
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`services`);
              }}
            >
              Services
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                setDrawer(false);
                navigate(`wards`);
              }}
            >
              Wards
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                navigate(`beds`);
                setDrawer(false);
              }}
            >
              Ward Beds
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                navigate(`insurance-companies`);
                setDrawer(false);
              }}
            >
              Accepted Insurance
            </p>
          </Dropdown.Item>
          <Dropdown.Item>
            <p
              className="nav-link"
              onClick={() => {
                navigate(`edit`);
                setDrawer(false);
              }}
            >
              Edit Institution
            </p>
          </Dropdown.Item>
        </Dropdown.Menu>
      </Dropdown>
      <hr />
    </>
  );
};

export default AdminNav;
